function showPassword(e){const i=e.previousElementSibling;"password"===i.type?(i.type="text",e.innerHTML='<i class="ri-eye-off-line"></i>'):(i.type="password",e.innerHTML='<i class="ri-eye-line"></i>')}function hideLoader(){window.addEventListener("load",(function(){const e=document.querySelector("#loader");e.style.opacity=0,setTimeout((()=>{e.style.display="none"}),300)}))}hideLoader();